def test_tc_trk_005_stability_closed(can_bus):
    msgs = collect_bcm_messages(can_bus, 10.0)
    assert all(get_trunk_status(m.data) == 0 for m in msgs)

def test_tc_trk_006_stability_open(can_bus):
    msgs = collect_bcm_messages(can_bus, 10.0)
    assert all(get_trunk_status(m.data) == 1 for m in msgs)

def test_tc_trk_007_valid_values(can_bus):
    msgs = collect_bcm_messages(can_bus, 5.0)
    for m in msgs:
        assert get_trunk_status(m.data) in (0, 1)

def test_tc_trk_008_cycles(can_bus):
    states = set()
    end_time = time.time() + 10.0
    while time.time() < end_time:
        msg = can_bus.recv(timeout=0.1)
        if msg and msg.arbitration_id == BCM_CAN_ID:
            states.add(get_trunk_status(msg.data))
    assert {0, 1}.issubset(states)

def test_tc_trk_010_bit_4_only(can_bus):
    msgs = collect_bcm_messages(can_bus, 5.0)
    prev_raw = None
    for m in msgs:
        curr_raw = m.data[0]
        if prev_raw is not None and curr_raw != prev_raw:
            assert (curr_raw ^ prev_raw) == (1 << TRUNK_STATUS_BIT)
        prev_raw = curr_raw
